export default {
  data: function data() {
    return {
      dialogVisible: false,
      form: {
        account: "",
        oldPassword: "",
        newPassword1: "",
        newPassword2: ""
      }
    };
  },
  methods: {
    updatePassword: function updatePassword() {
      var _this = this;

      this.$http.post("/api/loginCtl/updatePassword", jsonToString(this.form)).then(function (resp) {
        console.log(resp.data);

        if (_this.form.newPassword1.length == 0 || _this.form.newPassword2.length == 0) {
          _this.$message({
            message: '密码不能为空',
            type: 'warning',
            duration: 1000
          }); //出现时间


          return;
        }

        if (resp.data.code == 0) {
          _this.$message({
            message: '密码错误,请重新输入',
            type: 'warning',
            duration: 1000
          }); //出现时间


          return;
        }

        if (resp.data.code == 1) {
          _this.$message({
            message: '密码输入不一致,请重新输入',
            type: 'warning',
            duration: 1000
          }); //出现时间


          return;
        }

        if (resp.data.code == 2) {
          _this.$message({
            message: '新密码与旧密码一致,请重新输入',
            type: 'warning',
            duration: 1000
          }); //出现时间


          return;
        }

        _this.$message({
          message: '修改成功,请重新登录',
          type: 'success',
          duration: 1000,
          onClose: function onClose() {
            //关闭窗口
            _this.dialogVisible = false; //清除浏览器中存储的用户信息

            sessionStorage.clear(); //clear清除所有
            //跳转到注册页面

            _this.$router.push("/login");
          }
        });
      });
    }
  },
  mounted: function mounted() {
    //查询当前登录信息
    this.form.account = sessionStorage.getItem("account");
  }
};

function jsonToString(form) {
  var str = "";

  for (var s in form) {
    str += s + "=" + form[s] + "&";
  }

  return str.substring(0, str.length - 1);
}
